"use strict";(globalThis.webpackChunkgsf_docusaurus_template=globalThis.webpackChunkgsf_docusaurus_template||[]).push([[2350],{4920(e){e.exports=JSON.parse('{"tag":{"label":"persona:front-end-engineer","permalink":"/tags/persona-front-end-engineer","allTagsPath":"/tags","count":15,"items":[{"id":"catalog/development/web-performance/avoid-excessive-dom-size","title":"Avoid an excessive DOM size","description":"The greater the amount of nodes that are defined in HTML, the greater the time spent processing and rendering each element.","permalink":"/catalog/development/web-performance/avoid-excessive-dom-size"},{"id":"catalog/development/web-performance/avoid-chaining-critical-requests","title":"Avoid chaining critical requests","description":"Most web experiences require a lot of work from the user\'s browser. The greater the length of the chains and the larger the download sizes, the more significant the impact on page load performance and the energy required to render a page.","permalink":"/catalog/development/web-performance/avoid-chaining-critical-requests"},{"id":"catalog/development/data-handling/avoid-tracking-unnecessary-data","title":"Avoid tracking unnecessary data","description":"User tracking, user data collection and targeting in things like advertisements are responsible for significant energy use in many digital products, and services.","permalink":"/catalog/development/data-handling/avoid-tracking-unnecessary-data"},{"id":"catalog/development/data-handling/cache-static-data","title":"Cache static data","description":"From an energy-efficiency perspective, it\'s better to reduce network traffic by reading the data locally through a cache rather than accessing it remotely over the network. Shortening the distance a network packet travels means that less energy is required to transmit it. Similarly, from an embodied carbon perspective, we are more efficient with hardware when a network packet traverses through less computing equipment.","permalink":"/catalog/development/data-handling/cache-static-data"},{"id":"catalog/development/data-handling/compress-transmitted-data","title":"Compress transmitted data","description":"From an energy-efficiency perspective, it\'s better to minimise the size of the data transmitted so that less energy is required because the network traffic is reduced.","permalink":"/catalog/development/data-handling/compress-transmitted-data"},{"id":"catalog/development/media-and-code-efficiency/defer-offscreen-images","title":"Defer offscreen images","description":"Web pages offer a lot of images that aren\'t displayed on the first loaded screen and can thus be loaded dynamically.","permalink":"/catalog/development/media-and-code-efficiency/defer-offscreen-images"},{"id":"catalog/development/media-and-code-efficiency/deprecate-gifs","title":"Deprecate GIFs for animated content","description":"One direct replacement of the GIF is the MP4 video format which provides much smaller file sizes and higher quality at the same time.","permalink":"/catalog/development/media-and-code-efficiency/deprecate-gifs"},{"id":"catalog/development/web-performance/keep-request-counts-low","title":"Keep request counts low","description":"Accessing a web page usually retrieves a HTML file from the web server. The HTML may then reference additional resources that the browser has to download.","permalink":"/catalog/development/web-performance/keep-request-counts-low"},{"id":"catalog/development/web-performance/minify-web-assets","title":"Minify web assets","description":"Minification removes unnecessary or redundant data without affecting how the resource is processed by the web browser.","permalink":"/catalog/development/web-performance/minify-web-assets"},{"id":"catalog/development/web-performance/minimize-main-thread-work","title":"Minimize main thread work","description":"Description","permalink":"/catalog/development/web-performance/minimize-main-thread-work"},{"id":"catalog/development/media-and-code-efficiency/properly-sized-images","title":"Optimize image size","description":"Ideally, the stored pixel dimensions are exactly the same, or smaller, as the display size in pixels so that no bandwidth or storage space is wasted.","permalink":"/catalog/development/media-and-code-efficiency/properly-sized-images"},{"id":"catalog/development/data-handling/reduce-transmitted-data","title":"Reduce transmitted data","description":"From an energy-efficiency perspective, it\'s better to minimize the size of the data transmitted so that less energy is required because the network traffic is reduced.","permalink":"/catalog/development/data-handling/reduce-transmitted-data"},{"id":"catalog/development/media-and-code-efficiency/remove-unused-css","title":"Remove unused CSS definitions","description":"CSS files are very complex and need energy intensive parsing and processing. Each added CSS definition increases the amount of time and processing power needed in this process.","permalink":"/catalog/development/media-and-code-efficiency/remove-unused-css"},{"id":"catalog/development/media-and-code-efficiency/serve-images-in-modern-formats","title":"Serve images in modern formats","description":"Modern image formats can help to reduce bandwidth, storage and computing requirements on the displaying device.","permalink":"/catalog/development/media-and-code-efficiency/serve-images-in-modern-formats"},{"id":"catalog/development/web-performance/use-server-side-rendering","title":"Use server-side rendering for high-traffic pages","description":"Use server-side rendering for high-traffic pages","permalink":"/catalog/development/web-performance/use-server-side-rendering"}],"unlisted":false}}')}}]);